public int minArrays(int[] nums) {
    int n = nums.length;
    int totalGcd = nums[0];
    for (int i = 1; i < n; ++i) {
        totalGcd = gcd(totalGcd, nums[i]);
    }
    return (totalGcd == 1) ? 2 : 1;
}

public int gcd(int a, int b) {
    return (b == 0) ? a : gcd(b, a % b);
}
